moonbit_bytes_t epoxy_glGetString(void *fp, uint32_t name) {
  const unsigned char *(*f)(unsigned int) = (const unsigned char *(*)(unsigned int))fp;
  const unsigned char *s = f((unsigned int)name);
  if (!s) return moonbit_make_bytes(0, 0);
  size_t len = strlen((const char *)s);
  moonbit_bytes_t out = moonbit_make_bytes((int32_t)len, 0);
  memcpy(out, s, len);
  return out;
}

